
















































.BlueBottom {
  position: relative;
  .Bottom {
    display: flex;
    background-image: -moz-linear-gradient( 0deg, rgb(25,19,101) 0%, rgb(25,22,63) 52%, rgb(25,25,25) 100%);
    background-image: -webkit-linear-gradient( 0deg, rgb(25,19,101) 0%, rgb(25,22,63) 52%, rgb(25,25,25) 100%);
    background-image: -ms-linear-gradient( 0deg, rgb(25,19,101) 0%, rgb(25,22,63) 52%, rgb(25,25,25) 100%);
    background-image: linear-gradient( 0deg, rgb(25,19,101) 0%, rgb(25,22,63) 52%, rgb(25,25,25) 100%);
    height: 30px;
    bottom: 0px;
    z-index: 999;
    width: 100%;
    opacity: 0.9;
    div {
      display: flex;
      width: 50%;
      height: 40px;
      color: white;
      span {
        text-align: center;
        display: block;
        margin: auto;
        font-weight: 100;
        margin-top: 7px;
        font-size: 12px;
      }
    }
    .specialRight {
      span {
        display: block;
        float: right;
        margin-right: 15%;
        font-weight: 100;
      }
    }
    .specialLeft {
      span {
        display: block;
        float: left;
        margin-left: 15%;
        font-weight: 100;
      }
    }
  }
}
